module RefModule(clk, rst_n, out);input clk, rst_n;
    output [3:0] out;

    reg [3:0] obf_count;

    always @(posedge clk, negedge rst_n) begin
        if(!rst_n) begin
            obf_count <= 4'b0;
        end else begin
            if(obf_count == 4'b1111) begin
                obf_count <= 4'b0;
            end else begin
                obf_count <= obf_count + 1;
            end
        end
    end

    assign out = obf_count;

endmodule
